window.__QUIZ_DATA__=[{"id":"objective>Geography>2022>1","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of NONSO DISTRICT and use it  to answer the question below.       What is the scale of the map in statement form?","images":["data:image/png;base64,"],"options":{"A":"One centimetre on the map represents 1/2 kilometre on the ground","B":"One centimetre on the map represents 1 kilometre on the ground","C":"One centimetre on the map represents 2 kilometres on the ground","D":"One centimetre on the map represents 5 kilometres on the ground"},"answer":"A","explanation":"From the map given, the scale is 1:50,000. This implies that 1cm on the map represent 50,000cm on the ground. Note that 50,000 cm is equivalent to 500m or 0.5km or 1/2km .  \u2192 1cm on map represent 1/2km on ground","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>2","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Study the map of NONSO DISTRICT and use it  to answer the question below.     The growth of NONSO settlement is probably because","images":["data:image/png;base64,"],"options":{"A":"NONSO settlement has a court","B":"NONSO is situated at the foot of a ridge","C":"NONSO is a port town","D":"NONSO is a nodal town"},"answer":"D","explanation":"The growth of NONSO settlement is probably because NONSO is a nodal town. A nodal town or region is a point where certain activities(school, court, market, etc) are found at a centralized location","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>3","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of NONSO DISTRICT and use it  to answer the question below.     The highest spot on the mapped area is approximately","images":["data:image/png;base64,"],"options":{"A":"1300 metres","B":"1250 metres","C":"1150 metres","D":"1050 metres"},"answer":"B","explanation":"The highest spot on the map is approximately 1250m. This can be seen on the map around North East(NE)","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>4","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of NONSO DISTRICT and use it  to answer the question below.     The distance as the crow flies from Bukola to Balu is approximately","images":["data:image/png;base64,"],"options":{"A":"2.8 km","B":"3.8 km","C":"4.8 km","D":"7.8 km"},"answer":"C","explanation":"The distance as the crow flies from Bukola to Balu is approximately 4.8km","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>5","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of NONSO DISTRICT and use it  to answer the question below.     The commercial centre in the mapped area is","images":["data:image/png;base64,"],"options":{"A":"NONSO","B":"Adaku","C":"Bukola","D":"Balu"},"answer":"A","explanation":"The commercial centre in the mapped area is NONSO. At this point we have a market; a school and a court sited there.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>6","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of NONSO DISTRICT and use it  to answer the question below.     The watershed in the mapped area is situated","images":["data:image/png;base64,"],"options":{"A":"on the plain","B":"along the pass","C":"on spurs","D":"on the ridge"},"answer":"C","explanation":"The watershed in the mapped area is situated on spurs","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>7","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of NONSO DISTRICT and use it  to answer the question below.     If the map is reduced by half its original size, what would be the scale of the new map?","images":["data:image/png;base64,"],"options":{"A":"1: 25,000","B":"1: 50,000","C":"1: 100,000","D":"1: 150,000"},"answer":"C","explanation":"The original scale of the map says 1:50,000. This implies that 1cm on the map represent 50,000cm on the ground. Therefore if the map is reduced by half, then the new scale will be 0.5:50,000.  N.B: 0.5:50,000\u22611:100,000(by multiplying by 2)","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>8","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of NONSO DISTRICT and use it  to answer the question below.     What is the direction of flow of River Juth?","images":["data:image/png;base64,"],"options":{"A":"Northeast","B":"Northwest","C":"Southeast","D":"Southwest"},"answer":"B","explanation":"The direction of flow of River Juth is Northwest","marks":"1","difficulty":"1"},{"id":"objective>Geography>2022>9","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map of NONSO DISTRICT and use it  to answer the question below.     What is the contour interval on the mapped area?","images":["data:image/png;base64,"],"options":{"A":"50 metres","B":"100 metres","C":"200 metres","D":"300 metres"},"answer":"B","explanation":"The contour interval on the mapped area is 100 metres. It should be noted that contour interval is the difference in value between two adjacent contour lines","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>10","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Study the map of NONSO DISTRICT and use it  to answer the question below.     Which of the following settlements is nucleated?","images":["data:image/png;base64,"],"options":{"A":"Bukola","B":"Datsu","C":"Adaku","D":"NONSO"},"answer":"D","explanation":"NONSO is characterized as a nuclear or nucleated settlement. This is because NONSO settlement feature a close grouping of buildings. These buildings are gathered around a central feature like a road as seen in the map.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>11","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"Figure 1 represents the export of rice by four regions in country XX in the year 2009. One dot represents 20,000 tonnes of exported rice was used as the scale of the dot map. Study and use the dot map below to answer the question      Which region exported the highest tonnes of rice?","images":["data:image/png;base64,"],"options":{"A":"R","B":"U","C":"S","D":"T"},"answer":"A","explanation":"Region R exported the highest tonnes of rice. This is because it has the highest number of dots which represent the tonnes of exported rice","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>12","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"Figure 1 represents the export of rice by four regions in country XX in the year 2009. One dot represents 20,000 tonnes of exported rice was used as the scale of the dot map. Study and use the dot map below to answer the question  By how much tonnes was the export of rice from region T higher than that from region U?","images":[],"options":{"A":"20, 000","B":"40,000","C":"60,000","D":"80,000"},"answer":"D","explanation":"N.B: One dot = 20,000 tonnes  Region T = 7 dots =140,000 tonnes  Region U = 3 dots = 60,000 tonnes  Difference = 80 tonnes","marks":"1","difficulty":"3"},{"id":"objective>Geography>2022>13","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Figure 1 represents the export of rice by four regions in country XX in the year 2009. One dot represents 20,000 tonnes of exported rice was used as the scale of the dot map. Study and use the dot map below to answer the question  The total export of rice for regions R and T is","images":[],"options":{"A":"180,000 tonnes","B":"210,000 tonnes","C":"260,000 tonnes","D":"340,000 tonnes"},"answer":"D","explanation":"To get the total export of rice for regions R and T, you are going to add up the tonnes of rice for each region  Region R = 10 dots = 200,0000 tonnes  Region T = 7 dots = 140,0000 tonnes  Total = 340,000 tonnes","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>14","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"The sharp pillars hanging from the roof of a cavern in limestone regions are called","images":[],"options":{"A":"dolines","B":"stalagmites","C":"uvalas","D":"stalactites"},"answer":"D","explanation":"The sharp pillars hanging from the root of a cavern in limestone regions are called Stalactites. A stalactite is a mineral formation that hangs from the ceiling of caves.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2022>15","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Two towns, P and Q, are on the International Date Line and in the same hemisphere. If the distance between the two towns is 444 km and town P is located on latitude 3oN, on what latitude is town Q located?","images":[],"options":{"A":"10oN","B":"7oN","C":"4oN","D":"1oN"},"answer":"B","explanation":"Recall: The distance between two points on the same hemisphere or longitude = \u2296/360 x  2 x 22/7 x 6,371  \u2296 = 4o  The difference in latitude = 4o  Since they are on the same pole, it implies that    \u2296q - 3 = 4  \u2296q = 4 + 3 = 7oN","marks":"1","difficulty":"3"},{"id":"objective>Geography>2022>16","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"In Koppens's classification of climates, Cs refers to","images":[],"options":{"A":"Steppe","B":"Mediterranean","C":"Tropical Monsoon","D":"Tropical Continental"},"answer":"B","explanation":"In K\u00f6ppen's climate classification, Cs refers to the Mediterranean climate. This climate is characterized by hot, dry summers and mild, wet winters. The 'C' in Cs stands for warm temperate climates, and the 's' stands for dry summer.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>17","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Lines drawn on maps joining places with equal amount of cloud cover are called","images":[],"options":{"A":"isohyets","B":"isobars","C":"isonephs","D":"contours"},"answer":"C","explanation":"Lines drawn on maps joining places with equal amount of cloud cover are called isonephs. The term 'isoneph' comes from the Greek words 'iso' (equal) and 'nephos' (cloud). This is a type of isoline map, where each line (isoneph) represents a constant value of cloud cover.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>18","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following statements is accurate?","images":[],"options":{"A":"There is a distance of 111 km for every 1o of latitudinal difference.","B":"A time difference of 4 minutes exists for every 15o of longitude","C":"Any two opposite lines of latitudes make a Great Circle","D":"The sun is overhead at noon at Tropic of Cancer on December 22"},"answer":"A","explanation":"The statement 'There is a distance of 111 km for every 1 degree of latitudinal difference' is accurate. This is because the Earth's circumference is approximately 40,075 kilometers and there are 360 degrees in a circle. So, if you divide 40,075 by 360, you get approximately 111 kilometers. This is the average distance per degree of latitude.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2022>19","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following coastal features is not due to erosion?","images":[],"options":{"A":"Bay","B":"Cliff","C":"Beach","D":"Arch"},"answer":"A","explanation":"Bay is not a feature that is due to erosion. Other features due to erosion include stack, arch, cliff, caves, beaches, mudflats","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>20","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"In its old stage, a river would  I. be interrupted by waterfalls and rapids  II. flow sluggishly and develop pronounced meanders  III. flow fast and have truncated spurs  IV. develop leaves and have a flood plain","images":[],"options":{"A":"II and IV only","B":"II and III only","C":"I and II only","D":"III and IV only"},"answer":"A","explanation":"A river in its old stage often flows slowly or sluggishly through a very broad, flat floodplain that is curved. A river in this stage mostly erodes its sides causing changes in its meanders like the Mississippi","marks":"1","difficulty":"3"},{"id":"objective>Geography>2022>21","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The movement of the earth that causes variation in the lengths of the day and night is","images":[],"options":{"A":"traction","B":"revolution","C":"rotation","D":"coriolis"},"answer":"C","explanation":"The movement of the earth that causes variation in the lengths of the day and night is rotation. It should be noted that one of the consequences of  the rotation of the earth is Difference in Day and Night","marks":"1","difficulty":"1"},{"id":"objective>Geography>2022>22","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"It is crescentic in shape and it is formed from wind deposition in arid region.  The statement above describes","images":[],"options":{"A":"loess","B":"barchan dune","C":"alluvial soil","D":"silty soil"},"answer":"B","explanation":"The barchan dune is a cresent-shaped dune produced by the action of wind predominantly from one direction. It is mostly found in desert or arid regions.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>23","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The type of cloud from which thunder storms and heavy rain are experienced in the Tropics is","images":[],"options":{"A":"altostratus","B":"cirrus","C":"cumulus","D":"cumulo-nimbus"},"answer":"D","explanation":"Cumulonimbus clouds are associated with extreme weather such as heavy torrential downpour, hail, storms, lightening and even tornadoes","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>24","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which type of mountain is also called the mountain of denudation?","images":[],"options":{"A":"Block mountain","B":"Volcanic mountain","C":"Residual mountain","D":"Fold mountain"},"answer":"C","explanation":"Another term for mountain of denudation is residual mountain. This is because residual mountains are such type of mountains which are formed by the action of denudation agents such as running water, ice, wind etc. on the already existing mountain.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2022>25","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Which of the followingis a process of wind erosion?","images":[],"options":{"A":"Deflation","B":"Saltation","C":"Solution","D":"Traction"},"answer":"A","explanation":"Deflation is a process of wind erosion. It involves the removal and lifting of individual loose particles from the ground surface by the wind. This process can result in the creation of desert pavement, a surface covered with closely packed, interlocking angular or rounded rock fragments of pebble and cobble size.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>26","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"The weathering process which is commonly found in limestone regions is","images":[],"options":{"A":"hydrolysis","B":"exfoliation","C":"oxidation","D":"solution"},"answer":"D","explanation":"Solution(a sub-type of chemical weathering) is the process by which certain minerals are dissolved by acidic solutions. For example, calcite in limestone is dissolved easily by carbonic acid. Rain that percolates through cracks and fissures in limestone beds dissolve calcite, making wider cracks that can ultimately develop into a care system","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>27","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following statements is not accurate about sea and land breeze?","images":[],"options":{"A":"Air blows from the sea to the land during the day","B":"Air blows from the land to the sea during the night","C":"Land warms up more slowly than the sea during the day","D":"Sea warms up more slowly than the land during the day"},"answer":"C","explanation":"The statement 'Land warms up more slowly than the sea during the day' is not accurate about sea and land breeze. In fact, the land warms up faster than the sea during the day. This is because water has a higher specific heat capacity than land, meaning it takes longer for it to heat up and cool down. During the day, the land heats up faster than the sea, causing the air above it to rise and create a low-pressure area. The cooler, denser air over the sea then moves in to replace it, creating a sea breeze.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>28","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"The term pyroclastic best describes","images":[],"options":{"A":"sediments accumulated in deep sea","B":"a wind-blown sand from desert regions","C":"eroded materials deposited at the mouth of a river","D":"fragmented materials ejected by volcanoes"},"answer":"D","explanation":"\"Pyroclastic\" is a term which is used to describe fragments that are formed due to volcanic eruption.  N.B: Pyro= Fire, Clastic=Fragments","marks":"1","difficulty":"3"},{"id":"objective>Geography>2022>29","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"It is composed of layers of ash and cinders alternating with lava. It has a broad base and steep convex slopes. The above features are associated with a","images":[],"options":{"A":"batholith","B":"laccolith","C":"shield volcano","D":"composite cone"},"answer":"D","explanation":"the characteristics of composite volcanoes also known as stratovolcanoes are:  -cone shape with steep sides/slopes  -made of layers of hardened cinder, larva   -most violent eruptions of all volcano type  -high altitude(up to 8,000ft)  -erupts from one large vent or a clustered group of vents in a summit crater","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>30","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the following pairs are characteristics of igneous rocks? They  I. are stratified  II. are metamorphosed rocks  III. are crystalline  IV. originate from molten magma","images":[],"options":{"A":"I and II only","B":"II and III only","C":"II and IV only","D":"III and IV only"},"answer":"D","explanation":"Igneous rocks are formed from molten magma. Also, they are glassy and coarse i.e they are crystalline. Igneous rocks do not react with acids. They do not contain fossils and are not stratified.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>31","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"A small difference between the readings of the wet and dry bulb thermometer is an indication of","images":[],"options":{"A":"low relative humidity","B":"condensed air","C":"saturated air","D":"high relative humidity"},"answer":"D","explanation":"If  a small difference is recorded between the temperature of a wet-bulb thermometer and the dry-bulb thermometer of a hygrometer, it simply denotes that the relative humidity is high.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>32","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which of the following climatic features describes the Equatorial climate?","images":[],"options":{"A":"Double maxima rainfall regime","B":"Winter rain, summer drought","C":"Hot and dry throughout the year","D":"Single maximum rainfall regime"},"answer":"A","explanation":"The equatorial climate have double maxima rainfall(of 2000mm on average) around April and October each year.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2022>33","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"The formation of block mountains are best associated with","images":[],"options":{"A":"accumulation of materials ejected from within the earth crust","B":"solidification of magma within the earth's crust","C":"uplifting of crustal block within two parallel faults","D":"vertical movement of sediments into geosynclines"},"answer":"C","explanation":"Block mountains are formed when two tectonic plates move away from each other causing cracks on the surface of the earth. When parallel cracks or faults occur, the strip of land or the block of land between them may be raised resulting in the formation of block mountains","marks":"1","difficulty":"3"},{"id":"objective>Geography>2022>34","subject":"Geography","year":"2022","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following landforms is not associated with an advancing shoreline?","images":[],"options":{"A":"spit","B":"stack","C":"beach","D":"tombolo"},"answer":"B","explanation":"A stack is a geological landform consisting of a steep and often vertical column or columns of rock in the sea near a coast, formed by wave erosion. Stacks are formed over time by wind and water, processes of coastal geomorphology. They are formed when part of a headland is eroded by hydraulic action, which is the force of the sea or water crashing against the rock. So, it is associated with a retreating shoreline, not an advancing one.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>35","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"The term relative location of settlement refers to","images":[],"options":{"A":"imaginary point of the settlement","B":"the nature of the buildings within  the settlement","C":"the position of buildings in relation to other buildings","D":"the position of settlements in relation to others"},"answer":"D","explanation":"The term relative location of a settlement refers to the position of a settlement in relation to others.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>36","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"A major cause of rapid population growth rate in Tropical Africa is","images":[],"options":{"A":"improved transport facilities","B":"much pressure on land","C":"malnutrition and diseases","D":"lack of family planning"},"answer":"D","explanation":"Lack of family planning i.e uncontrolled natality is a major cause of rapid population growth in Tropical Africa","marks":"1","difficulty":"3"},{"id":"objective>Geography>2022>37","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"The most significant factor that led to the revolution in the Japanese industrial sector is the","images":[],"options":{"A":"presence of huge copper mines","B":"existence of vast oil and gas fields","C":"military strength of the countries that aided them","D":"inputs of committed and skillful industrial workforce"},"answer":"D","explanation":"The most significant factor that led to the revolution in the Japanese industrial sector is the inputs of committed and skillful industrial workspace","marks":"1","difficulty":"3"},{"id":"objective>Geography>2022>38","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Which of the following reasons accounts for the low traffic on rivers in Africa?","images":[],"options":{"A":"Presence of rapids and waterfalls","B":"Only used for fishing","C":"Wide valleys","D":"Change of colour during rainy seasons"},"answer":"A","explanation":"This is because most Africa rivers contains many waterfalls and impenetrable rapids and thus are not suitable for navigation","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>39","subject":"Geography","year":"2022","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"The trade liberalization policy of ECOWAS is aimed at","images":[],"options":{"A":"fostering unity and peace among member states","B":"taking a common stand on the world issues","C":"promoting economic integration","D":"ensuring cultural cooperation"},"answer":"C","explanation":"ECOWAS Trade Liberalization Scheme(ETLS) is a trade instrument designed by the ECOWAS. The scheme offers unhindered market access to fifteen member countries and promote economic relations or integrations within the sub-region.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>40","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Which of the following is a factor of population growth?","images":[],"options":{"A":"Climate","B":"Relief","C":"Birth rate","D":"Soil fertility"},"answer":"C","explanation":"Birth rate or Natality is a factor of population growth. High birth rate causes high population growth and vice versa","marks":"1","difficulty":"1"},{"id":"objective>Geography>2022>41","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"The least important factor in the location of settlements is the availability of","images":[],"options":{"A":"surface water","B":"mineral deposits","C":"land for building","D":"fertile soil"},"answer":"A","explanation":"Surface water is a least important factor in the location of settlements","marks":"1","difficulty":"1"},{"id":"objective>Geography>2022>42","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"If the total population of a country is 75,000,000 and its total land area is 250,000 km2, what is its population density?","images":[],"options":{"A":"30 persons per km2","B":"300 persons per km2","C":"350 persons per km2","D":"500 persons per km2"},"answer":"B","explanation":"Parameters given:  Population = 75,000,000  land area = 250,000km2  Population density = unknown  recall; Population Density = Population/Area  =Population Density= 75,000,000/250,000  =300 persons per km2","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>43","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"A major hindrance to foreign investment in Tropical African countries is","images":[],"options":{"A":"low demand for manufactured goods","B":"inadequate raw materials for industries","C":"political instability in the countries","D":"inadequate capital for investment"},"answer":"C","explanation":"Political instability in a country can deter foreign investors as it creates an uncertain environment for business. This can lead to loss of investments due to conflicts, changes in policies, and lack of rule of law. Therefore, political instability is a major hindrance to foreign investment in Tropical African countries.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>44","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"One of the major problems of manufacturing industries in Tropical Africa is","images":[],"options":{"A":"high quality of the industrial labour","B":"high cost of labour","C":"inadequate raw materials","D":"overproduction of manufactured goods"},"answer":"C","explanation":"Inadequacy of the raw materials needed to manufacture is a MAJOR PROBLEM that manufacturing industries face in Tropical Africa","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>45","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"The transport system which is most affected by climatic factors is","images":[],"options":{"A":"water transport","B":"rail transport","C":"road transport","D":"air transport"},"answer":"D","explanation":"Air transport is a transport system which is mostly affected by climatic factors-wind, pressure, humidity etc.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>46","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The term overpopulation could best be described as a situation where","images":[],"options":{"A":"there is high population density","B":"birth rate  is equal to death rate","C":"the population exceeds the available resources","D":"there is an increasing birth rate and a decreasing infant mortality rate"},"answer":"C","explanation":"In the case of overpopulation, the population, i.e the number of people in a geographical location exceeds the resources available to cater for their existence","marks":"1","difficulty":"3"},{"id":"objective>Geography>2022>47","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"The best way of solving transportation problems in a cosmopolitan city is","images":[],"options":{"A":"use of air transport system","B":"construction of feeder roads","C":"purchase of many speed boats and ships","D":"integrated transport system involving all modes"},"answer":"D","explanation":"A cosmopolitan city is where people from various parts of the world live, with different languages, cultures and customs.  The best way of solving transportation problems in a cosmopolitan city is integrated transport system involving all modes.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>48","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Transportation helps economic development through all the following except the","images":[],"options":{"A":"diffusion of ideas and technology","B":"promotion of national and international trade","C":"movement of people and commodities","D":"distribution of population"},"answer":"D","explanation":"Economic development is not helped or fostered by transportation through the distribution of population","marks":"1","difficulty":"1"},{"id":"objective>Geography>2022>49","subject":"Geography","year":"2022","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Which of the following is the leading industrial zone in the West African sub region?","images":[],"options":{"A":"Western industrial zone of Nigeria","B":"Accra-Tema industrial zone of Ghana","C":"Freetown industrial zone of Sierra leone","D":"Banjul industrial zone of The Gambia"},"answer":"B","explanation":"Accra-Tema industrial zone of Ghana is the leading industrial zone in West Africa sub region","marks":"1","difficulty":"2"},{"id":"objective>Geography>2022>50","subject":"Geography","year":"2022","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following is a light industry?","images":[],"options":{"A":"Petroleum industry","B":"Metallurgical industry","C":"Textile industry","D":"Shipbuilding industry"},"answer":"C","explanation":"Light industry is an industry that usually is less capital-intensive than heavy industry and is more consumer-oriented than business-oriented, as they typically produce smaller consumer goods.  Example of light industry is the textile industry","marks":"1","difficulty":"1"}];